  "messages": [{
    "role": "user",
    "content": "Extract invoice data from this document:\n\n{{ $json.text || $('New Invoice Email').item.json.text }}\n\nReturn JSON: {\"vendor_name\": \"\", \"vendor_email\": null, \"invoice_number\": \"\", \"invoice_date\": \"YYYY-MM-DD\", \"due_date\": null, \"line_items\": [{\"description\": \"\", \"quantity\": 1, \"unit_price\": 0, \"total\": 0}], \"subtotal\": 0, \"tax_amount\": null, \"total_amount\": 0, \"currency\": \"USD\", \"payment_terms\": null, \"purchase_order_number\": null}"
  }]
