parameters.jsCode:
const raw = $input.item.json.content[0].text;
const parsed = JSON.parse(raw);

// Validation flags
const flags = [];
const MAX_INVOICE = 50000;

if (parsed.total_amount > MAX_INVOICE) {
  flags.push(`Amount $${parsed.total_amount} exceeds threshold $${MAX_INVOICE}`);
}
if (parsed.total_amount <= 0) {
  flags.push('Invalid amount: zero or negative');
}

// Check if invoice date is more than 90 days old
if (parsed.invoice_date) {
  const invoiceDate = new Date(parsed.invoice_date);
  const daysDiff = (Date.now() - invoiceDate.getTime()) / (1000 * 60 * 60 * 24);
  if (daysDiff > 90) {
    flags.push(`Invoice date is ${Math.round(daysDiff)} days old`);
  }
}

parsed.flags = flags;
parsed.needs_review = flags.length > 0;
parsed.received_at = new Date().toISOString();
parsed.source_email = $('New Invoice Email').item.json.id;

return { json: parsed };

