parameters.jsCode:
const myDomain = 'yourdomain.com'; // CHANGE THIS
const items = $input.all();
const externalMeetings = [];

for (const item of items) {
  const event = item.json;
  if (!event.attendees || event.attendees.length === 0) continue;

  const externalAttendees = event.attendees.filter(a => 
    a.email && !a.email.includes(myDomain) && !a.email.includes('resource.calendar.google.com')
  );

  if (externalAttendees.length > 0) {
    externalMeetings.push({
      id: event.id,
      title: event.summary,
      start: event.start?.dateTime || event.start?.date,
      end: event.end?.dateTime || event.end?.date,
      external_attendees: externalAttendees.map(a => ({
        name: a.displayName || a.email.split('@')[0],
        email: a.email,
        company: a.email.split('@')[1]
      }))
    });
  }
}

return externalMeetings.map(m => ({ json: m }));

